mapper.select:
SELECT COUNT(1)
FROM TAG_MASTER
WHERE TAG_CODE = #{value}

mapper.insert:
INSERT INTO USER_TAG_MAP (
	MAPPING_NO, USER_NO, QUESTION_ID, TAG_CODE
)
SELECT
	SEQ_USER_TAG_MAP_NO.NEXTVAL,
	ua.USER_NO,
	#{questionId},
	#{tagCode}
FROM USER_AUTHENTICATION ua
WHERE ua.USER_AUTH_ID = #{authId}
  AND NOT EXISTS (
	SELECT 1
	FROM USER_TAG_MAP utm
	WHERE utm.USER_NO = ua.USER_NO
	  AND utm.TAG_CODE = #{tagCode}
)

mapper.delete:
DELETE FROM USER_TAG_MAP
WHERE USER_NO = (
	SELECT ua.USER_NO
	FROM USER_AUTHENTICATION ua
	WHERE ua.USER_AUTH_ID = #{authId}
)
  AND TAG_CODE = #{tagCode}

mapper.insert:
INSERT INTO USER_TAG_MAP (
	MAPPING_NO, USER_NO, QUESTION_ID, TAG_CODE
)
SELECT
	SEQ_USER_TAG_MAP_NO.NEXTVAL,
	#{userNo},
	#{questionId},
	#{tagCode}
FROM DUAL
WHERE NOT EXISTS (
	SELECT 1
	FROM USER_TAG_MAP utm
	WHERE utm.USER_NO = #{userNo}
	  AND utm.TAG_CODE = #{tagCode}
)

mapper.select:
SELECT USER_NICKNAME
FROM USERS
WHERE USER_NO = #{value}
